      artist: "oreth",
      program: "electronic-artefacts",
      medium: ["Audio", "Writing"],
      discipline: ["Music", "Narrative", "Research"],
      description:
        "PALIMPSESTS is a conceptual album structured in five acts. It moves from origins to remembrance, from lived experience to transcendence, and finally to heritage: the quiet persistence of what remains.",
      summary: "Conceptual album in five acts about memory, inheritance and transmission.",
      coreIdea:
        "PALIMPSESTS is an album about traces: what appears, what is remembered, what is lived, what changes, and what survives.",
      theme: "Five-act meditation on memory and transmission",
      subThemes: ["Origins", "Remembrance", "Experiences", "Transcendence", "Heritage", "Memory", "Time", "Inheritance", "Transformation", "Persistence"],
      originOfTitle:
        "A palimpsest is a reused manuscript where one text is erased and another is written over it, yet the earlier traces remain.",
      centralQuestion: "What remains of a life once it has been rewritten by time?",
      secondaryQuestions: [
        "What do we inherit?",
        "What survives the act of forgetting?",
        "How do memories change shape?",
        "How does a life remain visible in its traces?",
      ],
      orethStructure: {
        note: "The work is framed as a five-act cycle, moving from emergence to inheritance through a single editorial arc.",
        cycles: [
          { letter: "I", title: "Origins" },
          { letter: "II", title: "Remembrance" },
          { letter: "III", title: "Experiences" },
          { letter: "IV", title: "Transcendence" },
          { letter: "V", title: "Heritage" },
        ],
        currentMaterial: ["Intro", "Entropy", "Emergence", "Palimpsest", "Incandescence", "Keraunos", "Les Étoiles Meurent Pour Toi", "CtrlC+CtrlV", "Forever Each Other", "Rustr", "Running Up That Hill", "Now", "La Nuit", "Soft Control", "Out Of Memory", "Crash", "Resilience"],
      },
      acts: [
        {
          title: "Act I — Origins",
          subtitle: "Before the worlds",
          mood: "Drone · Ambient",
          description:
            "Origins explores the conditions that precede form. Before language, before history, before memory. The act is concerned with emergence itself: the gradual appearance of structure from disorder.",
          tracks: ["Intro", "Entropy", "Emergence"],
          keywords: ["Entropy", "Formation", "Emergence", "Genesis", "Signal", "Chaos"],
        },
        {
          title: "Act II — Remembrance",
          subtitle: "The first accounts",
          mood: "Voice · Electronica · Ambient",
          description:
            "If Origins concerns the birth of structures, Remembrance concerns what remains. Memories. Stories. Archives. Myths. The title track sits at the center of the album like an overwritten page.",
          tracks: ["Palimpsest", "Incandescence", "Keraunos", "Les Étoiles Meurent Pour Toi"],
          keywords: ["Memory", "Archive", "Inheritance", "History", "Transmission", "Remains"],
        },
        {
          title: "Act III — Experiences",
          subtitle: "Experiences of events and relations",
          mood: "Analog · Voice · Grungy",
          description:
            "After origins and foundational narratives comes the age of individual lives. The myths recede. Relationships, absence, love, desire, memory and loss take their place. The music becomes more embodied, intimate and rougher around the edges.",
          tracks: ["CtrlC+CtrlV", "Forever Each Other", "Rustr", "Running Up That Hill", "Now", "La Nuit"],
          keywords: ["Humanity", "Love", "Desire", "Memory", "Perception", "Relationship", "Emotion"],
        },
        {
          title: "Act IV — Transcendence",
          subtitle: "Machine point of view",
          mood: "Algorithmic · Techno · Synthetic",
          description:
            "Transcendence leaves the strictly human domain and begins to examine systems that extend beyond it. Control structures. Algorithms. Automation. Feedback loops. The language cools, the rhythms become more precise, and the perspective grows detached.",
          tracks: ["Soft Control", "Out Of Memory", "Crash"],
          keywords: ["Control", "Systems", "Algorithms", "Networks", "Transformation", "Hybridisation"],
        },
        {
          title: "Act V — Heritage",
          subtitle: "Compiled artefacts",
          mood: "Ultra Minimal · Pure Techno",
          description:
            "Heritage closes the cycle. After emergence, memory, experience and transformation, only traces remain. The final track compresses the album into a distilled artefact carrying fragments of everything that came before it.",
          tracks: ["Resilience"],
          keywords: ["Legacy", "Transmission", "Persistence", "Resilience", "Inheritance", "Future"],
        },
      ],
      musicalLanguage: ["Drone", "Ambient", "Voice", "Electronica", "Analog", "Grungy", "Algorithmic", "Techno", "Ultra Minimal", "Pure Techno"],
      visualLanguage: ["Black", "Ivory", "Grey", "Navy blue"],
      textures: ["Paper", "Dust", "Archives", "Light", "Sky", "Smoke"],
